INSERT IGNORE INTO `shop_print_docs` VALUES (1,'1947','1948','sales_receipt','[]','[{\"caption\":\"Отобразить кнопку печати документа для покупателя\",\"name\":\"button_visible_for_customer\",\"type\":\"checkbox\"},{\"caption\":\"Продавец\",\"type\":\"textarea\",\"name\":\"seller\"},{\"caption\":\"Покупатель\",\"type\":\"user_profile_json_builder\",\"name\":\"customer\",\"hint\":\"Распечатать товарный чек может только зарегистрированный покупатель. Укажите здесь поля профиля пользователя для каждого типа учетной записи, значения которых должны выводиться в соответствующий блок распечатываемого документа\"},{\"caption\":\"Основание\",\"type\":\"text\",\"name\":\"basis_of_payment\",\"hint\":\"Основанием обычно служит договор купли-продажи товаров. Если Вы не хотите отображать этот реквизит в документе, оставьте поле пустым\"},{\"caption\":\"НДС, % (включенный в сумму заказа)\",\"type\":\"text\",\"name\":\"nds\",\"hint\":\"Если чек нужен БЕЗ НДС - оставьте это поле пустым\"},{\"caption\":\"Пояснение к чеку\",\"type\":\"textarea\",\"name\":\"explanation\",\"hint\":\"Текстовое пояснение к чеку, которое выводится под таблицей товаров. Сюда Вы можете написать краткие условия поставки товаров. Если не требуется выводить пояснение - оставьте поле пустым\"},{\"caption\":\"Наименование ДЛ\",\"type\":\"text\",\"name\":\"dl_name\",\"hint\":\"Наименование должностного лица, подписывающего чек, например, Генеральный директор, Главный бухгалтер или Продавец\"},{\"caption\":\"Фамилия и инициалы ДЛ\",\"type\":\"text\",\"name\":\"dl_fio\",\"hint\":\"Фамилия и инициалы должностного лица, подписывающего документ\"},{\"caption\":\"Скан подписи (необязательно)\",\"type\":\"image_file\",\"name\":\"signature_scan\"},{\"caption\":\"Расшифровка подписи покупателя\",\"type\":\"user_profile_json_builder\",\"name\":\"customer_fio\"}]','{\"button_visible_for_customer\":1,\"seller\":\"\",\"customer\":{\"reg_variant_1\":null,\"reg_variant_2\":null,\"reg_variant_3\":null},\"basis_of_payment\":\"\\u0